private Map<String, Integer> initializeHeader() throws IOException {
    Map<String, Integer> hdrMap = null;
    final String[] formatHeader = this.format.getHeader();
    if (formatHeader != null) {
        hdrMap = new LinkedHashMap<String, Integer>();

        String[] header = null;
        if (formatHeader.length == 0) {
            // read the header from the first line of the file
            final CSVRecord nextRecord = this.nextRecord();
            if (nextRecord != null) {
                header = nextRecord.values();
            }
        } else {
            if (this.format.getSkipHeaderRecord()) {
                this.nextRecord();
            }
            header = formatHeader;
        }

        // build the name to index mappings
        if (header != null) {
            for (int i = 0; i < header.length; i++) {
                String trimmedHeader = header[i].trim();
                if (trimmedHeader.isEmpty()) {
                    throw new IllegalArgumentException("Empty header entry found at index: " + i);
                }
                if (hdrMap.containsKey(trimmedHeader)) {
                    throw new IllegalStateException("Duplicate header entry found: '" + trimmedHeader + "'");
                }
                hdrMap.put(trimmedHeader, Integer.valueOf(i));
            }
        }
    }
    return hdrMap;
}

private Map<String, Integer> initializeHeader() throws IOException {
    Map<String, Integer> hdrMap = null;
    final String[] formatHeader = this.format.getHeader();
    if (formatHeader != null) {
        hdrMap = new LinkedHashMap<String, Integer>();

        String[] header = null;
        if (formatHeader.length == 0) {
            // read the header from the first line of the file
            final CSVRecord nextRecord = this.nextRecord();
            if (nextRecord != null) {
                header = nextRecord.values();
            }
        } else {
            if (this.format.getSkipHeaderRecord()) {
                this.nextRecord();
            }
            header = formatHeader;
        }

        // build the name to index mappings
        if (header != null) {
            for (int i = 0; i < header.length; i++) {
                String headerValue = header[i];
                if (headerValue == null || headerValue.isEmpty()) {
                    throw new IllegalArgumentException("Header entry cannot be null or empty at index: " + i);
                }
                if (hdrMap.containsKey(headerValue)) {
                    throw new IllegalStateException("Duplicate header entry: " + headerValue);
                }
                hdrMap.put(headerValue, Integer.valueOf(i));
            }
        }
    }
    return hdrMap;
